1	import { createServer } from "node:net";
2	import { isMainThread, threadId } from "node:worker_threads";
3	
4	async function isPortFree(port: number): Promise<boolean> {
5	  if (!Number.isFinite(port) || port <= 0 || port > 65535) {
6	    return false;
7	  }
8	  return await new Promise((resolve) => {
9	    const server = createServer();
10	    server.once("error", () => resolve(false));
11	    server.listen(port, "127.0.0.1", () => {
12	      server.close(() => resolve(true));
13	    });
14	  });
15	}
16	
17	async function getOsFreePort(): Promise<number> {
18	  return await new Promise((resolve, reject) => {
19	    const server = createServer();
20	    server.once("error", reject);
21	    server.listen(0, "127.0.0.1", () => {
22	      const addr = server.address();
23	      if (!addr || typeof addr === "string") {
24	        server.close();
25	        reject(new Error("failed to acquire free port"));
26	        return;
27	      }
28	      const port = addr.port;
29	      server.close((err) => (err ? reject(err) : resolve(port)));
30	    });
31	  });
32	}
33	
34	let nextTestPortOffset = 0;
35	
36	/**
37	 * Allocate a deterministic per-worker port block.
38	 *
39	 * Motivation: many tests spin up gateway + related services that use derived ports
40	 * (e.g. +1/+2/+3/+4). If each test just grabs an OS free port, parallel test runs
41	 * can collide on derived ports and get flaky EADDRINUSE.
42	 */
43	export async function getDeterministicFreePortBlock(params?: {
44	  offsets?: number[];
45	}): Promise<number> {
46	  const offsets = params?.offsets ?? [0, 1, 2, 3, 4];
47	  const maxOffset = Math.max(...offsets);
48	
49	  const workerIdRaw = process.env.VITEST_WORKER_ID ?? process.env.VITEST_POOL_ID ?? "";
50	  const workerId = Number.parseInt(workerIdRaw, 10);
51	  const processShard = Math.abs(process.pid);
52	  const shard = Number.isFinite(workerId)
53	    ? Math.max(0, workerId) + processShard
54	    : isMainThread
55	      ? processShard
56	      : processShard + Math.abs(threadId);
57	
58	  const rangeSize = 1000;
59	  const shardCount = 35;
60	  const base = 30_000 + (Math.abs(shard) % shardCount) * rangeSize; // <= 59_999
61	  const usable = rangeSize - maxOffset;
62	
63	  // Allocate in blocks to avoid derived-port overlaps (e.g. port+3).
64	  const blockSize = Math.max(maxOffset + 1, 8);
65	
66	  // Scan in block-size steps. Tests consume neighboring derived ports (+1/+2/...),
67	  // so probing every single offset is wasted work and slows large suites.
68	  for (let attempt = 0; attempt < usable; attempt += blockSize) {
69	    const start = base + ((nextTestPortOffset + attempt) % usable);
70	    const ok = (await Promise.all(offsets.map((offset) => isPortFree(start + offset)))).every(
71	      Boolean,
72	    );
73	    if (!ok) {
74	      continue;
75	    }
76	    nextTestPortOffset = (nextTestPortOffset + attempt + blockSize) % usable;
77	    return start;
78	  }
79	
80	  // Fallback: let the OS pick a port block (best effort).
81	  for (let attempt = 0; attempt < 25; attempt += 1) {
82	    const port = await getOsFreePort();
83	    const ok = (await Promise.all(offsets.map((offset) => isPortFree(port + offset)))).every(
84	      Boolean,
85	    );
86	    if (ok) {
87	      return port;
88	    }
89	  }
90	
91	  throw new Error("failed to acquire a free port block");
92	}
93	
94	export async function getFreePortBlockWithPermissionFallback(params: {
95	  offsets: number[];
96	  fallbackBase: number;
97	}): Promise<number> {
98	  try {
99	    return await getDeterministicFreePortBlock({ offsets: params.offsets });
100	  } catch (err) {
101	    const code = (err as NodeJS.ErrnoException | undefined)?.code;
102	    if (code === "EPERM" || code === "EACCES") {
103	      return params.fallbackBase + (process.pid % 10_000);
104	    }
105	    throw err;
106	  }
107	}
